export function formatRequestDetails(details: {
  url?: string | undefined;
  method?: string | undefined;
  status?: number | undefined;
  durationMs?: number | undefined;
  body?: unknown;
  headers?: Record<string, string> | undefined;
}): Record<string, unknown> {
  const result: Record<string, unknown> = {};
  if (details.url) result['url'] = details.url;
  if (details.method) result['method'] = details.method;
  if (details.status) result['status'] = details.status;
  if (details.durationMs) result['durationMs'] = details.durationMs;
  if (details.headers) {
    result['headers'] = Object.fromEntries(
      Object.entries(details.headers).map(([k, v]) =>
        k.toLowerCase() === 'x-api-key' ? [k, '***'] : [k, v]
      )
    );
  }
  return result;
}
